function.arguments:
{"action":"write","content":"const express = require('express');
const { createServer } = require('http');
const { Server } = require('socket.io');
const si = require('systeminformation');
const path = require('path');

const app = express();
const httpServer = createServer(app);
const io = new Server(httpServer);

const PORT = process.env.PORT || 3000;

// Serve static files from the public directory
app.use(express.static(path.join(__dirname, 'public')));

// Stats collection function
async function getSystemStats() {
  try {
    const [cpuLoad, memData] = await Promise.all([
      si.currentLoad(),
      si.mem()
    ]);

    const cpuPercent = cpuLoad.currentLoad !== null ? parseFloat(cpuLoad.currentLoad.toFixed(1)) : 0;
    const memUsed = memData.used !== null ? Math.round(memData.used / 1024 / 1024) : 0; // MB
    const memTotal = memData.total !== null ? Math.round(memData.total / 1024 / 1024) : 0; // MB
    const memPercent = memTotal > 0 ? parseFloat(((memUsed / memTotal) * 100).toFixed(1)) : 0;

    return {
      cpu: {
        percent: cpuPercent
      },
      memory: {
        used: memUsed,
        total: memTotal,
        percent: memPercent
      },
      timestamp: Date.now()
    };
  } catch (error) {
    console.error('Error collecting system stats:', error);
    return {
      cpu: { percent: 0 },
      memory: { used: 0, total: 0, percent: 0 },
      timestamp: Date.now(),
      error: true
    };
  }
}

// Socket.IO connection handling
io.on('connection', (socket) => {
  console.log(`Client connected: ${socket.id}`);

  // Send initial stats immediately
  getSystemStats().then(stats => {
    socket.emit('stats', stats);
  });

  socket.on('disconnect', () => {
    console.log(`Client disconnected: ${socket.id}`);
  });
});

// Periodic stats emission to all connected clients
const STATS_INTERVAL = 1000; // 1 second
setInterval(async () => {
  const stats = await getSystemStats();
  io.emit('stats', stats);
}, STATS_INTERVAL);

// Start the server
httpServer.listen(PORT, () => {
  console.log(`System Monitor Server running on http://localhost:${PORT}`);
  console.log(`Press Ctrl+C to stop`);
});
","path":"server.js"}

