{"action":"write","content":"* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
  color: #e0e0e0;
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
  padding: 20px;
}

.container {
  width: 100%;
  max-width: 600px;
}

header {
  text-align: center;
  margin-bottom: 30px;
}

header h1 {
  font-size: 2rem;
  font-weight: 600;
  color: #ffffff;
  margin-bottom: 5px;
}

.subtitle {
  color: #a0a0a0;
  font-size: 0.95rem;
  margin-bottom: 12px;
}

.status {
  display: flex;
  justify-content: center;
  gap: 15px;
  font-size: 0.8rem;
  color: #888;
}

#connection-status {
  padding: 2px 10px;
  border-radius: 12px;
  font-weight: 500;
  transition: all 0.3s ease;
}

#connection-status.connected {
  background: #2ecc71;
  color: #fff;
}

#connection-status.disconnected {
  background: #e74c3c;
  color: #fff;
}

#connection-status.connecting {
  background: #f39c12;
  color: #fff;
}

.cards {
  display: grid;
  grid-template-columns: 1fr;
  gap: 20px;
  margin-bottom: 30px;
}

@media (min-width: 500px) {
  .cards {
    grid-template-columns: 1fr 1fr;
  }
}

.card {
  background: rgba(255, 255, 255, 0.05);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 16px;
  padding: 24px;
  backdrop-filter: blur(10px);
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.card:hover {
  transform: translateY(-3px);
  box-shadow: 0 8px 25px rgba(0, 0, 0, 0.3);
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 16px;
}

.card-header h2 {
  font-size: 1.1rem;
  font-weight: 500;
  color: #ffffff;
}

.icon {
  font-size: 1.4rem;
}

.card-body {
  text-align: center;
}

.stat-value {
  font-size: 2.8rem;
  font-weight: 700;
  color: #ffffff;
  line-height: 1;
  margin-bottom: 4px;
}

.stat-label {
  font-size: 0.85rem;
  color: #888;
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 16px;
}

.progress-bar {
  width: 100%;
  height: 10px;
  background: rgba(255, 255, 255, 0.1);
  border-radius: 5px;
  overflow: hidden;
  margin-bottom: 12px;
}

.progress-fill {
  height: 100%;
  border-radius: 5px;
  transition: width 0.5s ease, background-color 0.5s ease;
  background: linear-gradient(90deg, #3498db, #2ecc71);
}

.progress-fill.warning {
  background: linear-gradient(90deg, #f39c12, #e67e22);
}

.progress-fill.danger {
  background: linear-gradient(90deg, #e74c3c, #c0392b);
}

.stat-detail {
  font-size: 0.85rem;
  color: #a0a0a0;
}

footer {
  text-align: center;
  font-size: 0.75rem;
  color: #666;
}
","path":"public/style.css"}

{"action":"write","content":"(function() {
  'use strict';

  const cpuPercentEl = document.getElementById('cpu-percent');
  const cpuBarEl = document.getElementById('cpu-bar');
  const memPercentEl = document.getElementById('mem-percent');
  const memBarEl = document.getElementById('mem-bar');
  const memUsedEl = document.getElementById('mem-used');
  const memTotalEl = document.getElementById('mem-total');
  const statusEl = document.getElementById('connection-status');
  const lastUpdateEl = document.getElementById('last-update');

  function updateStatus(state, text) {
    statusEl.className = state;
    statusEl.textContent = text;
  }

  function formatTime(timestamp) {
    const d = new Date(timestamp);
    return d.toLocaleTimeString();
  }

  function updateBar(barEl, percent) {
    barEl.style.width = percent + '%';
    barEl.classList.remove('warning', 'danger');
    if (percent >= 80) {
      barEl.classList.add('danger');
    } else if (percent >= 60) {
      barEl.classList.add('warning');
    }
  }

  function updateStats(stats) {
    if (stats.error) {
      console.error('Received stats with error flag');
      return;
    }

    const cpu = stats.cpu.percent;
    const mem = stats.memory.percent;

    cpuPercentEl.textContent = cpu + '%';
    updateBar(cpuBarEl, cpu);

    memPercentEl.textContent = mem + '%';
    updateBar(memBarEl, mem);

    memUsedEl.textContent = stats.memory.used;
    memTotalEl.textContent = stats.memory.total;

    lastUpdateEl.textContent = 'Last update: ' + formatTime(stats.timestamp);
  }

  // Initialize Socket.IO connection
  const socket = io();

  socket.on('connect', function() {
    updateStatus('connected', 'Connected');
    console.log('Socket connected:', socket.id);
  });

  socket.on('disconnect', function(reason) {
    updateStatus('disconnected', 'Disconnected');
    console.log('Socket disconnected:', reason);
  });

  socket.on('connect_error', function(err) {
    updateStatus('disconnected', 'Connection Error');
    console.error('Socket connection error:', err.message);
  });

  socket.on('stats', function(stats) {
    updateStats(stats);
  });

  updateStatus('connecting', 'Connecting...');
})();
","path":"public/app.js"}

